import{_ as o,I as a,o as t,c as r,j as i,a as l,J as n,ap as c}from"./chunks/framework.ockA5sXJ.js";const f=JSON.parse('{"title":"Migrating to Citizen 4","description":"Preview the Citizen 4 changes and migrate your wiki before the release","frontmatter":{"title":"Migrating to Citizen 4","description":"Preview the Citizen 4 changes and migrate your wiki before the release"},"headers":[],"relativePath":"guide/migrating-to-citizen-4.md","filePath":"guide/migrating-to-citizen-4.md","lastUpdated":1783490799000}'),d={name:"guide/migrating-to-citizen-4.md"};function h(p,e,k,g,u,y){const s=a("CopyOrDownloadAsMarkdownButtons");return t(),r("div",null,[e[0]||(e[0]=i("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /mediawiki-skins-Citizen/guide/migrating-to-citizen-4.md for this page in Markdown format",-1)),e[1]||(e[1]=i("h1",{id:"migrating-to-citizen-4",tabindex:"-1"},[l("Migrating to Citizen 4 "),i("a",{class:"header-anchor",href:"#migrating-to-citizen-4","aria-label":"Permalink to “Migrating to Citizen 4”"},"​")],-1)),n(s),e[2]||(e[2]=c(`<p>Citizen 4.0 will ship breaking changes. This cycle, that means the new color token pipeline becoming the default — tokens are the CSS custom properties documented in <a href="./../customization/theming">Theming</a>. This guide walks you through migrating your wiki ahead of the release, using the <strong>preview channel</strong> to rehearse everything safely on your production wiki. Citizen majors ship alongside MediaWiki LTS releases, so there&#39;s a long runway — start whenever it suits you.</p><p>Preview features are production-quality, but their shape may change during the cycle — changes are announced in the release notes.</p><h2 id="try-it-in-your-browser" tabindex="-1">Try it in your browser <a class="header-anchor" href="#try-it-in-your-browser" aria-label="Permalink to “Try it in your browser”">​</a></h2><p>Append <code>?citizenpreview=4</code> to any page URL on your wiki. The choice persists in a 24-hour cookie for your browser only; readers are unaffected. Append <code>?citizenpreview=0</code> to switch back.</p><p>While previewing, check:</p><ul><li>Your site CSS (<code>MediaWiki:Citizen.css</code>, <code>MediaWiki:Common.css</code>) in <strong>both</strong> light and dark schemes</li><li>Gadgets that style or read skin colors</li><li>Any hardcoded colors that clash with the new palette</li></ul><div class="warning custom-block"><p class="custom-block-title">Shared caches</p><p>On wikis behind a CDN, the URL parameter varies the cache key but the <strong>cookie does not</strong>. Rehearse anonymous views via the URL parameter, or while logged in — logged-in traffic typically bypasses the CDN.</p></div><h2 id="fix-things-guarded" tabindex="-1">Fix things, guarded <a class="header-anchor" href="#fix-things-guarded" aria-label="Permalink to “Fix things, guarded”">​</a></h2><p>Write your migration fixes inside a <code>:root.citizen-v4</code> guard. Guarded rules are inert for stable readers and active in preview — safe to deploy immediately:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root.citizen-v4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    --color-surface-1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: light-dark( </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#f7f2ea</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#201d18</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> );</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Note the two-value <code>light-dark()</code> form — a single value would silently break dark mode; see <a href="#light-and-dark-are-one-declaration-now">Light and dark are one declaration now</a>.</p><p>The <code>citizen-v4</code> class stays on <code>&lt;html&gt;</code> through the <strong>whole 4.x lifetime</strong>, so your guarded fixes keep applying after you upgrade. Unguard them at your leisure during 4.x; the class is removed in 5.0. The guard itself survives the upgrade, but if a preview feature&#39;s shape changes during the cycle — see the rebrand note below — you may still need to update what&#39;s inside it.</p><p>Gadget JavaScript can detect the channel the same way:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> isCitizen4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> document.documentElement.classList.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">contains</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;citizen-v4&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> );</span></span></code></pre></div><h2 id="wiki-wide-preview" tabindex="-1">Wiki-wide preview <a class="header-anchor" href="#wiki-wide-preview" aria-label="Permalink to “Wiki-wide preview”">​</a></h2><p>Once your rehearsal looks clean, you can put the whole wiki on the preview with <a href="./../config/#wgcitizenpreview"><code>$wgCitizenPreview</code></a>:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title="LocalSettings.php">LocalSettings.php</span></div><div class="language-php"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$wgCitizenPreview </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div></div><p>Only the value <code>4</code> activates the preview during this cycle; <code>0</code> or any other value keeps the stable experience. The URL parameter and cookie take precedence over the config, so individual browsers can still switch back with <code>?citizenpreview=0</code> while the wiki is on the preview.</p><h2 id="migrating-your-token-overrides" tabindex="-1">Migrating your token overrides <a class="header-anchor" href="#migrating-your-token-overrides" aria-label="Permalink to “Migrating your token overrides”">​</a></h2><p>Most token names are unchanged — the big shift is <strong>how</strong> values resolve.</p><h3 id="light-and-dark-are-one-declaration-now" tabindex="-1">Light and dark are one declaration now <a class="header-anchor" href="#light-and-dark-are-one-declaration-now" aria-label="Permalink to “Light and dark are one declaration now”">​</a></h3><p>The new pipeline defines colors as <code>light-dark()</code> pairs and drives them with <code>color-scheme</code>. A plain override wins in <strong>both</strong> schemes and silently breaks dark mode:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Breaks dark mode: applies this light value in both schemes */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root.citizen-v4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    --color-surface-0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#fffaf0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Correct: provide both halves */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root.citizen-v4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    --color-surface-0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: light-dark( </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#fffaf0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#16130e</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> );</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="your-css-still-wins" tabindex="-1">Your CSS still wins <a class="header-anchor" href="#your-css-still-wins" aria-label="Permalink to “Your CSS still wins”">​</a></h3><p>Citizen&#39;s new tokens live in a CSS cascade layer (<code>@layer citizen-tokens</code>). Site CSS is unlayered, and unlayered styles beat layered ones — your <code>:root</code> overrides always win without specificity tricks. This is by design.</p><h3 id="removed-tokens" tabindex="-1">Removed tokens <a class="header-anchor" href="#removed-tokens" aria-label="Permalink to “Removed tokens”">​</a></h3><p>A diff of the two pipelines&#39; compiled stylesheets shows 58 custom properties removed. All of them are internal color math. The legacy pipeline decomposed each color into separate channel properties (lightness, chroma, saturation, hue) and computed surface and state shades from them with <code>calc()</code>; the new pipeline ships static <code>light-dark()</code> pairs instead, so the intermediates no longer exist. <strong>No surface, text, border, or background token is removed</strong> — if you only ever overrode tokens like <code>--color-surface-1</code> or <code>--color-base</code>, this section doesn&#39;t affect you.</p><p>Overriding a removed property is a silent no-op in the preview. Four of them were global tuning knobs, so they get their own migration advice:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Removed token</th><th style="text-align:left;">What to do instead</th></tr></thead><tbody><tr><td style="text-align:left;"><code>--delta-lightness-hover-state</code></td><td style="text-align:left;">No replacement — hover shades are no longer computed. Override the affected state token directly, as a <code>light-dark()</code> pair (for example <code>--color-surface-1--hover</code>).</td></tr><tr><td style="text-align:left;"><code>--delta-lightness-active-state</code></td><td style="text-align:left;">Same, for active shades (for example <code>--color-surface-1--active</code>).</td></tr><tr><td style="text-align:left;"><code>--delta-lightness-state-base</code></td><td style="text-align:left;">The base value the hover and active deltas derived from. Same guidance.</td></tr><tr><td style="text-align:left;"><code>--delta-lightness-surface-base</code></td><td style="text-align:left;">Stepped the surface ramp (<code>--color-surface-1</code> to <code>--color-surface-4</code>) away from the page background. Override the surface tokens directly.</td></tr></tbody></table><p>The remaining 54 are per-color channel decompositions. If you overrode one of them to retune a color, override the color token itself now. Two of them (<code>--color-progressive-oklch__l</code> and <code>--color-progressive-oklch__c</code>) are the primary-color rebrand knobs from the <a href="./../customization/theming#primary-color">Theming</a> guide — see <a href="#rebranding-the-primary-color">Rebranding the primary color</a> below.</p><details class="details custom-block"><summary>Full list of removed internal tokens</summary><p>Channel key: <code>__l</code> lightness, <code>__c</code> chroma, <code>__s</code> saturation, <code>__h</code> hue.</p><p><strong>OKLCH channel properties (24):</strong></p><ul><li><code>--color-base-oklch__c</code>, <code>--color-base-oklch__l</code></li><li><code>--color-disabled-oklch__c</code>, <code>--color-disabled-oklch__l</code></li><li><code>--color-emphasized-oklch__c</code>, <code>--color-emphasized-oklch__l</code></li><li><code>--color-placeholder-oklch__c</code>, <code>--color-placeholder-oklch__l</code></li><li><code>--color-progressive-oklch__c</code>, <code>--color-progressive-oklch__l</code></li><li><code>--color-subtle-oklch__c</code>, <code>--color-subtle-oklch__l</code></li><li><code>--color-surface-0-oklch__c</code>, <code>--color-surface-0-oklch__l</code></li><li><code>--color-surface-1-oklch__c</code>, <code>--color-surface-1-oklch__l</code></li><li><code>--color-surface-2-oklch__c</code>, <code>--color-surface-2-oklch__l</code></li><li><code>--color-surface-3-oklch__c</code>, <code>--color-surface-3-oklch__l</code></li><li><code>--color-surface-4-oklch__c</code>, <code>--color-surface-4-oklch__l</code></li><li><code>--shadow-color-oklch__c</code>, <code>--shadow-color-oklch__l</code></li></ul><p><strong>HSL channel properties (22):</strong></p><ul><li><code>--color-base-hsl__l</code>, <code>--color-base-hsl__s</code></li><li><code>--color-disabled-hsl__l</code>, <code>--color-disabled-hsl__s</code></li><li><code>--color-emphasized-hsl__l</code>, <code>--color-emphasized-hsl__s</code></li><li><code>--color-placeholder-hsl__l</code>, <code>--color-placeholder-hsl__s</code></li><li><code>--color-subtle-hsl__l</code>, <code>--color-subtle-hsl__s</code></li><li><code>--color-surface-0-hsl__l</code>, <code>--color-surface-0-hsl__s</code></li><li><code>--color-surface-1-hsl__l</code>, <code>--color-surface-1-hsl__s</code></li><li><code>--color-surface-2-hsl__l</code>, <code>--color-surface-2-hsl__s</code></li><li><code>--color-surface-3-hsl__l</code>, <code>--color-surface-3-hsl__s</code></li><li><code>--color-surface-4-hsl__l</code>, <code>--color-surface-4-hsl__s</code></li><li><code>--shadow-color-hsl__l</code>, <code>--shadow-color-hsl__s</code></li></ul><p><strong>Standalone channel properties (8):</strong></p><ul><li><code>--background-color-subtle__l</code>, <code>--background-color-subtle__s</code></li><li><code>--color-destructive__h</code>, <code>--color-destructive__l</code></li><li><code>--color-success__h</code>, <code>--color-success__l</code></li><li><code>--color-warning__h</code>, <code>--color-warning__l</code></li></ul></details><p>Every other custom property the legacy pipeline defines is also emitted by the new one under the same name. The diff also adds 170 properties that only exist in the new pipeline — mostly the primitive color ramps everything is now built from, plus additional state variants.</p><h3 id="rebranding-the-primary-color" tabindex="-1">Rebranding the primary color <a class="header-anchor" href="#rebranding-the-primary-color" aria-label="Permalink to “Rebranding the primary color”">​</a></h3><p>In Citizen 3, the <a href="./../customization/theming#primary-color">Theming</a> guide&#39;s rebrand recipe was to override the progressive channel properties — usually just the hue. The new pipeline builds the primary color differently: a single hue property, <code>--color-primary-oklch__h</code>, generates a full ramp of primary shades (<code>--color-primary-50</code> through <code>--color-primary-1000</code>), and semantic tokens like <code>--color-progressive</code> pick their light and dark stops from that ramp.</p><p>Here is how the old knobs map:</p><ul><li><strong>Hue</strong> (<code>--color-progressive-oklch__h</code>): still emitted as an alias of the new property, so styles that <em>read</em> it keep resolving — but overriding it no longer changes the skin. Move your override to <code>--color-primary-oklch__h</code>. The value stays the same, and since it&#39;s a plain hue angle rather than a color, it doesn&#39;t need a <code>light-dark()</code> pair:</li></ul><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Citizen 3 */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    --color-progressive-oklch__h</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">150</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Citizen 4 preview */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root.citizen-v4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    --color-primary-oklch__h</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">150</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><strong>Lightness and chroma</strong> (<code>--color-progressive-oklch__l</code>, <code>--color-progressive-oklch__c</code>): removed. Each ramp stop bakes in its own lightness and chroma, so there is no single knob anymore. If the hue alone doesn&#39;t get you there, override the semantic tokens (<code>--color-progressive</code>, <code>--color-progressive--hover</code>, <code>--color-progressive--active</code>) directly with <code>light-dark()</code> pairs.</li></ul><p>The hue also does more than before: UI surfaces carry a subtle tint of it by default. A second knob, <code>--color-neutral-oklch__h</code>, controls that tint: it defaults to the primary hue, and setting it to a different value decouples the chrome from the accent (for example, gray chrome with a colorful accent).</p><p>The soft-deprecated HSL fallback properties (<code>--color-progressive-hsl__h</code>, <code>__s</code>, <code>__l</code>) are still emitted for the few styles that read them, but they no longer feed the accent color anywhere — migrate to the new hue property.</p><p>One caveat: of everything in the preview, the retheme surface is the most likely to still evolve before 4.0 ships — keep an eye on the release notes and the <a href="./../customization/theming">Theming</a> guide.</p><p>Whichever way it evolves, guarded fixes stay inert until a reader is on the preview, and <code>?citizenpreview=0</code> reverts your own browser instantly.</p>`,42))])}const _=o(d,[["render",h]]);export{f as __pageData,_ as default};
